/// <summary>
///
/// </summary>
/// <returns></returns>
public boolean validateWrite()
{
    boolean ret = super();

    if (ret) // Only continue if base validation passed
    {
        // Ensure weights are valid numeric values
        if (this.GrossWeight < this.NetWeight)
        {
            checkFailed("Gross Weight cannot be less than Net Weight.");
            ret = false;
        }

        if (this.LineNum == 0)
        {
            checkFailed("Sl No cannot be zero.");
            ret = false;
        }

        if (this.Bags == 0)
        {
            checkFailed("Number of bags cannot be zero.");
            ret = false;
        }
    }

    return ret;
}

/// <summary>
///
/// </summary>
EcoResItemColorName grade()
{
    CustPackingSlipJour     custPackingSlipJour;
    CustPackingSlipTrans    custPackingSlipTrans;
    ;

    select firstonly custPackingSlipJour where
    custPackingSlipJour.SalesId == this.SalesId && custPackingSlipJour.PackingSlipId == this.PackingSlipId;

    select firstonly custPackingSlipTrans where
    custPackingSlipTrans.SalesId == custPackingSlipJour.SalesId &&
    custPackingSlipTrans.PackingSlipId == custPackingSlipJour.PackingSlipId &&
    custPackingSlipTrans.DeliveryDate == custPackingSlipJour.DeliveryDate;

    return custPackingSlipTrans.inventDim().InventColorId;
}

Name itemDesc()
{
    CustPackingSlipJour     custPackingSlipJour;
    CustPackingSlipTrans    custPackingSlipTrans;
    ;

    select firstonly custPackingSlipJour where
    custPackingSlipJour.SalesId == this.SalesId && custPackingSlipJour.PackingSlipId == this.PackingSlipId;

    select firstonly custPackingSlipTrans where
    custPackingSlipTrans.SalesId == custPackingSlipJour.SalesId &&
    custPackingSlipTrans.PackingSlipId == custPackingSlipJour.PackingSlipId &&
    custPackingSlipTrans.DeliveryDate == custPackingSlipJour.DeliveryDate;

