}

TransTxt package()
{
    CustPackingSlipJour     custPackingSlipJour;
    CustPackingSlipTrans    custPackingSlipTrans;
    WMSBillOfLadingCarrier  wmsBillOfLadingCarrier;
    ;

    select firstonly custPackingSlipJour where
    custPackingSlipJour.SalesId == this.SalesId && custPackingSlipJour.PackingSlipId == this.PackingSlipId;

    select firstonly custPackingSlipTrans where
    custPackingSlipTrans.SalesId == custPackingSlipJour.SalesId &&
    custPackingSlipTrans.PackingSlipId == custPackingSlipJour.PackingSlipId &&
    custPackingSlipTrans.DeliveryDate == custPackingSlipJour.DeliveryDate;

    select firstonly wmsBillOfLadingCarrier where wmsBillOfLadingCarrier.billOfLadingId == custPackingSlipJour.BillOfLadingId;

    return strfmt('%1 in %2', custPackingSlipTrans.inventDim().configId, wmsBillOfLadingCarrier.packageAppearance);
}

SalesUnit unitId()
{
    CustPackingSlipJour     custPackingSlipJour;
    CustPackingSlipTrans    custPackingSlipTrans;
    ;

    select firstonly custPackingSlipJour where
    custPackingSlipJour.SalesId == this.SalesId && custPackingSlipJour.PackingSlipId == this.PackingSlipId;

    select firstonly custPackingSlipTrans where
    custPackingSlipTrans.SalesId == custPackingSlipJour.SalesId &&
    custPackingSlipTrans.PackingSlipId == custPackingSlipJour.PackingSlipId &&
    custPackingSlipTrans.DeliveryDate == custPackingSlipJour.DeliveryDate;

    return custPackingSlipTrans.SalesUnit;
}
